@using NonFactors.Mvc.Grid;
@using System.Data;

@model Firstronic.Areas.Personnel.Models.Bonus_History


@{
  DateTime dia_current = new DateTime(Model.stardate.Year, Model.stardate.Month, Model.stardate.Day);
  DateTime dia_current_end = new DateTime(Model.enddate.Year, Model.enddate.Month, Model.enddate.Day);
}

@section head{
  <style nonce="@Html.ScriptNonce()">
    header {
      display: none !important;
      height: 0px !important;
    }

    .main-content {
      padding-top: 0px !important;
    }

    footer {
      display: none !important;
      height: 0px !important;
    }
  </style>
}

  <div class="row  mt-2">
    <div class="col-12 mvc-grid p-0">
      @{
        System.Data.SqlClient.SqlParameter[] parameters = new System.Data.SqlClient.SqlParameter[]
        { };
        DataTable auditors = Firstronic.Framework.Queries.GetDatatableFromQuery(@"SELECT ASPU.Badge FROM [PERSONEL_BONUS_USER_LOCK] QSL INNER JOIN ASPNETUSERS ASPU ON ASPU.Plexus_User_No = QSL.ID", parameters);
        DataTable dt = Firstronic.Framework.Functions.Others.GetBonusRange(dia_current, dia_current_end, "0", Model.Gafete); // Assume this method returns the datatable from service
        DataTable dt2 = dt.Clone();
        dt2.Columns["FlowID"].DataType = Type.GetType("System.Int32");

        foreach (DataRow dr in dt.Rows)
        {
          dt2.ImportRow(dr);
        }
        dt2.AcceptChanges();
        DataView dv = dt2.DefaultView;
        dv.Sort = "Bonus_Type_ID DESC,FlowID ASC,Station ASC, Shift ASC";
        DataTable sortedDT = dv.ToTable();

        sortedDT.Columns.RemoveAt(1);
        //sortedDT.Columns.RemoveAt(0);

        sortedDT.Columns.RemoveAt(sortedDT.Columns.Count - 3);
        sortedDT.Columns.RemoveAt(sortedDT.Columns.Count - 1);


        sortedDT.Columns.Add("Gana", typeof(int));

        sortedDT.Columns["Bonus_Type_ID"].ColumnName = "Type";

        foreach (DataRow fila in sortedDT.Rows)
        {
          if (int.Parse(fila["Type"].ToString()) == 8)
          {
            fila["Gana"] = int.Parse(fila["Effi"].ToString());
          }
          if (int.Parse(fila["Effi"].ToString()) >= 85)
          {
            fila["Gana"] = 40;
          }
          else
          {
            fila["Gana"] = 0;
          }
          if ((fila["Station"].ToString()) == "CALIDAD")
          {
            string dtGafete = fila["Gafete"].ToString();
            string gafeteNumerico = dtGafete.StartsWith("R") ?
                                   dtGafete.Substring(1).TrimStart('0').TrimEnd('A') :
                                   dtGafete.TrimStart('0').TrimEnd('A');

            bool exist = auditors.AsEnumerable().Any(row =>
            {
              string badge = row["Badge"].ToString();
              string GafeteNum = badge.StartsWith("R") ?
                                   badge.Substring(1).TrimStart('0') :
                                   badge.TrimStart('0');

              return badge == dtGafete ||
                     GafeteNum == gafeteNumerico;
            });

            fila["Gana"] = exist ? 0 : 30;
          }
        }
      }


      <table border="1">
        <thead>
          <tr>
            @{
              int colin = 0;
            }
            @foreach (System.Data.DataColumn col in sortedDT.Columns)
            {

              <th>@col.Caption</th>
              colin++;
            }
          </tr>
        </thead>
        <tbody>
          @foreach (System.Data.DataRow rowstation in sortedDT.Rows)
          {
            <tr>
              @{
                int varcell1 = 1;

                foreach (var cell in rowstation.ItemArray)
                {
                  if (varcell1 == 28)
                  {
                    int per1 = int.Parse(rowstation[27].ToString());

                    string dw_time = "dw-0";

                    if (per1 >= 95)
                    {
                      dw_time = "dw-0";
                    }
                    else if (per1 >= 90)
