@section head
{
  <style nonce="@Html.ScriptNonce()">
    .report-section {
      margin-bottom: 30px;
    }

    .filter-section {
      background-color: #f5f5f5;
      padding: 20px;
      border-radius: 4px;
      margin-bottom: 20px;
    }

    .warning-section {
      background-color: #fff3cd;
      border-left: 4px solid #ffc107;
      padding: 15px;
      margin-bottom: 20px;
    }

    .role-members-table {
      width: 100%;
      border-collapse: collapse;
    }

    .role-members-table th,
