    .role-members-table th {
      background-color: #007bff;
      color: white;
      font-weight: bold;
    }

    .role-members-table tbody tr:nth-child(even) {
      background-color: #f2f2f2;
    }

    .role-members-table tbody tr:hover {
      background-color: #e9ecef;
    }

    .expand-btn {
      cursor: pointer;
      color: #007bff;
      text-decoration: underline;
      background: none;
      border: none;
      padding: 0;
      font-size: inherit;
    }

    .expand-btn:hover {
      color: #0056b3;
    }

    .member-list {
      display: none;
      padding: 10px;
      background-color: #f8f9fa;
      margin-top: 5px;
      border: 1px solid #dee2e6;
      border-radius: 4px;
    }

    .member-list table {
      width: 100%;
      margin: 0;
    }

    .member-list th {
      background-color: #6c757d;
      color: white;
      padding: 6px;
      font-size: 0.9em;
    }

    .member-list td {
      padding: 6px;
      font-size: 0.9em;
