      background-color: #dc3545;
      color: white;
      padding: 2px 6px;
      border-radius: 3px;
      font-size: 0.8em;
    }

    .badge-active {
      background-color: #28a745;
      color: white;
      padding: 2px 6px;
      border-radius: 3px;
      font-size: 0.8em;
    }

    /* Print Styling */
    @media print {
      header,
      footer,
      .sidebar,
      .md-card-toolbar-actions,
      .noPrint,
      .filter-section {
        display: none !important;
      }

      .main-content {
        padding: 0 !important;
