@using Firstronic.Framework.Extensions
@using System.Web.Optimization
@using System.Configuration;
@using System.ServiceModel.Configuration;
@using Microsoft.AspNet.Identity
@using Microsoft.AspNet.Identity;
@using Microsoft.AspNet.Identity.Owin;
@using Firstronic.Framework.Account;

@{
  string title = ViewContext.RouteData.DataTokens["area"].ToString() + " Portal"; // Setting("general.site.name").Value;
  string description = Firstronic.Models.Settings.GeneralSettings.GetValue("general.site.name");
  string releasenumber = Firstronic.Models.Settings.GeneralSettings.GetValue("general.site.releasenumber");

  string titlepage = "";

  if (ViewBag.Title != null)
  {
    title = string.Format("{0} | {1}", ViewBag.Title, title);
    titlepage = ViewBag.Title;
  }
  else
  {
    var prefix = Html.RenderPageWrap("title").ToHtmlString();
    title = prefix.HasValue() ? string.Format("{0} | {1}", prefix, title) : title;

    ViewBag.Title = title;
  }

  if (ViewBag.Description != null)
  {
    description = ViewBag.Description;
  }

  ClientSection clientSection = (ClientSection)ConfigurationManager.GetSection("system.serviceModel/client");

  string address = "";
  bool testPlex = false;
  for (int i = 0; i < clientSection.Endpoints.Count; i++)
  {
    if (clientSection.Endpoints[i].Name == "ServiceSoap")
    {
      address = clientSection.Endpoints[i].Address.ToString();
      if (address.Contains("testapi."))
      {
        testPlex = true;
      }
    }
  }

